insert into l1_transfer_rules (id, l1, category, skill_id, title, cause, triggers, explanations, contrast, example_errors) values
  ('hi.article_omission', 'Hindi', 'grammar', 'gr.articles', 'Dropping articles (a / an / the)', 'Hindi has no articles, so learners often omit "a", "an", and "the".', '[{"kind":"regex","pattern":"\\b(i am|he is|she is|you are)\\s+(doctor|engineer|teacher|student|nurse|manager|driver)\\b"}]'::jsonb, '{"Hindi":"हिंदी में article नहीं होता, इसलिए a/an/the छूट जाता है। बोलिए: \"I am a doctor\"।"}'::jsonb, '{"l1Form":"main doctor hoon","l2Form":"I am a doctor"}'::jsonb, ARRAY['I am doctor','She is teacher']::text[]),
  ('hi.stative_progressive', 'Hindi', 'grammar', 'gr.stative_verbs', 'Using stative verbs in the -ing form', 'Hindi "main jaan raha hoon" maps to a progressive, but English keeps stative verbs simple.', '[{"kind":"regex","pattern":"\\bi am (knowing|understanding|wanting|liking|needing|believing|meaning)\\b"}]'::jsonb, '{"Hindi":"know, want, like जैसे stative verbs को continuous में नहीं कहते। \"I am knowing\" गलत है — कहिए \"I know\"।"}'::jsonb, '{"l1Form":"main jaanta hoon","l2Form":"I know"}'::jsonb, ARRAY['I am knowing the answer','I am wanting tea']::text[]),
  ('hi.uncountable_plural', 'Hindi', 'grammar', 'gr.countability', 'Pluralising uncountable nouns', 'English uncountable nouns feel countable in Hindi, producing "informations", "furnitures".', '[{"kind":"regex","pattern":"\\b(furnitures|informations|advices|equipments|luggages|softwares)\\b"}]'::jsonb, '{"Hindi":"\"information\", \"furniture\", \"advice\" uncountable हैं — इनका plural नहीं होता। कहिए \"some information\"।"}'::jsonb, '{"l1Form":"bahut saari informations","l2Form":"a lot of information"}'::jsonb, ARRAY['He gave me many informations','We bought new furnitures']::text[]),
  ('hi.universal_tag', 'Hindi', 'pragmatic', 'fn.tag_questions', 'Using "isn''t it?" as a universal tag', 'Hindi "na?" fits every sentence, so learners over-use "isn''t it?" as a catch-all tag.', '[{"kind":"regex","pattern":"isn''?t it\\b"}]'::jsonb, '{"Hindi":"हर वाक्य में \"isn''t it?\" मत लगाइए। Subject और verb के हिसाब से बदलता है: \"You''re coming, aren''t you?\""}'::jsonb, '{"l1Form":"tum aa rahe ho, na?","l2Form":"you''re coming, aren''t you?"}'::jsonb, ARRAY['You will join, isn''t it?','They are ready, isn''t it?']::text[]),
  ('hi.v_w_merge', 'Hindi', 'phonetic', 'ph.v_w_distinction', 'Merging /v/ and /w/', 'Hindi has one sound (व) for both /v/ and /w/, so "vine" and "wine" sound alike.', '[{"kind":"phoneme","pattern":"v~w"}]'::jsonb, '{"Hindi":"/v/ के लिए ऊपर के दाँत नीचे के होंठ पर लगाइए (very); /w/ के लिए होंठ गोल कीजिए (water)।"}'::jsonb, '{"l1Form":"व (one sound)","l2Form":"/v/ very vs /w/ water"}'::jsonb, ARRAY['wery good','I want some vater']::text[]),
  ('ta.article_omission', 'Tamil', 'grammar', 'gr.articles', 'Dropping articles (a / an / the)', 'Tamil has no articles, so "a", "an", and "the" are commonly omitted.', '[{"kind":"regex","pattern":"\\b(i am|he is|she is|you are)\\s+(doctor|engineer|teacher|student|nurse|manager|driver)\\b"}]'::jsonb, '{"Tamil":"தமிழில் article கிடையாது, அதனால் a/an/the விட்டுப்போகும். சொல்லுங்கள்: \"I am an engineer\"."}'::jsonb, '{"l1Form":"naan engineer","l2Form":"I am an engineer"}'::jsonb, ARRAY['I am doctor','She is teacher']::text[]),
  ('ta.sov_residue', 'Tamil', 'grammar', 'gr.word_order', 'Subject-Object-Verb order carried into English', 'Tamil is verb-final (SOV); English is SVO, so the verb sometimes lands at the end.', '[{"kind":"regex","pattern":"\\bi (english|tamil|hindi|telugu|kannada|malayalam|food|tea) (speaking|talking|eating|drinking)\\b"}]'::jsonb, '{"Tamil":"English-ல் verb முன்னால் வரும்: \"I am speaking English\" — \"I English speaking\" அல்ல."}'::jsonb, '{"l1Form":"naan English pesuren","l2Form":"I speak English"}'::jsonb, ARRAY['I English speaking','I food eating now']::text[]),
  ('ta.stative_progressive', 'Tamil', 'grammar', 'gr.stative_verbs', 'Using stative verbs in the -ing form', 'Dravidian aspect lets stative verbs take a continuous form that English does not.', '[{"kind":"regex","pattern":"\\bi am (knowing|understanding|wanting|liking|needing|believing|meaning)\\b"}]'::jsonb, '{"Tamil":"know, want, like போன்ற verbs-ஐ continuous-ல் சொல்லக்கூடாது. \"I am knowing\" தவறு — \"I know\"."}'::jsonb, '{"l1Form":"enakku theriyum","l2Form":"I know"}'::jsonb, ARRAY['I am knowing the answer','I am wanting tea']::text[]),
  ('ta.uncountable_plural', 'Tamil', 'grammar', 'gr.countability', 'Pluralising uncountable nouns', 'Some English uncountable nouns feel countable, producing "informations", "furnitures".', '[{"kind":"regex","pattern":"\\b(furnitures|informations|advices|equipments|luggages|softwares)\\b"}]'::jsonb, '{"Tamil":"\"information\", \"furniture\", \"advice\" uncountable — இவற்றுக்கு plural இல்லை. \"some information\"."}'::jsonb, '{"l1Form":"romba informations","l2Form":"a lot of information"}'::jsonb, ARRAY['He gave me many informations','We bought new furnitures']::text[]),
  ('ta.universal_tag', 'Tamil', 'pragmatic', 'fn.tag_questions', 'Using "isn''t it?" as a universal tag', 'A single Tamil tag fits everything, so "isn''t it?" gets over-used.', '[{"kind":"regex","pattern":"isn''?t it\\b"}]'::jsonb, '{"Tamil":"எல்லா வாக்கியத்திலும் \"isn''t it?\" சேர்க்க வேண்டாம். Subject, verb-ஐ பொறுத்து மாறும்: \"You''re coming, aren''t you?\""}'::jsonb, '{"l1Form":"varuvinga, illaya?","l2Form":"you''re coming, aren''t you?"}'::jsonb, ARRAY['You will join, isn''t it?','They are ready, isn''t it?']::text[]),
  ('ta.retroflex_stops', 'Tamil', 'phonetic', 'ph.retroflex_t_d', 'Retroflex /t/ /d/ for English alveolar', 'Tamil uses retroflex stops where English uses alveolar /t/ /d/.', '[{"kind":"phoneme","pattern":"t~d-retroflex"}]'::jsonb, '{"Tamil":"English /t/, /d/ — நாக்கை அண்ணத்தில் வைக்காமல், பல் பின்னால் லேசாக வையுங்கள். \"time\", \"day\"."}'::jsonb, '{"l1Form":"ட/ட் (retroflex)","l2Form":"alveolar t / d"}'::jsonb, ARRAY[' time','day']::text[]),
  ('te.article_omission', 'Telugu', 'grammar', 'gr.articles', 'Dropping articles (a / an / the)', 'Telugu has no articles, so "a", "an", and "the" are commonly omitted.', '[{"kind":"regex","pattern":"\\b(i am|he is|she is|you are)\\s+(doctor|engineer|teacher|student|nurse|manager|driver)\\b"}]'::jsonb, '{"Telugu":"తెలుగులో article ఉండదు, అందుకే a/an/the వదిలేస్తారు. చెప్పండి: \"I am an engineer\"."}'::jsonb, '{"l1Form":"nenu engineer","l2Form":"I am an engineer"}'::jsonb, ARRAY['I am doctor','She is teacher']::text[]),
  ('te.sov_residue', 'Telugu', 'grammar', 'gr.word_order', 'Subject-Object-Verb order carried into English', 'Telugu is verb-final (SOV); English is SVO, so the verb can land at the end.', '[{"kind":"regex","pattern":"\\bi (english|tamil|hindi|telugu|kannada|malayalam|food|tea) (speaking|talking|eating|drinking)\\b"}]'::jsonb, '{"Telugu":"English-లో verb ముందు వస్తుంది: \"I am speaking English\" — \"I English speaking\" కాదు."}'::jsonb, '{"l1Form":"nenu English maatladtanu","l2Form":"I speak English"}'::jsonb, ARRAY['I English speaking','I food eating now']::text[]),
  ('te.stative_progressive', 'Telugu', 'grammar', 'gr.stative_verbs', 'Using stative verbs in the -ing form', 'Dravidian aspect allows a continuous form for stative verbs that English does not.', '[{"kind":"regex","pattern":"\\bi am (knowing|understanding|wanting|liking|needing|believing|meaning)\\b"}]'::jsonb, '{"Telugu":"know, want, like లాంటి verbs ను continuous లో చెప్పకూడదు. \"I am knowing\" తప్పు — \"I know\"."}'::jsonb, '{"l1Form":"naaku telusu","l2Form":"I know"}'::jsonb, ARRAY['I am knowing the answer','I am wanting tea']::text[]),
  ('te.uncountable_plural', 'Telugu', 'grammar', 'gr.countability', 'Pluralising uncountable nouns', 'Some English uncountable nouns feel countable, producing "informations", "furnitures".', '[{"kind":"regex","pattern":"\\b(furnitures|informations|advices|equipments|luggages|softwares)\\b"}]'::jsonb, '{"Telugu":"\"information\", \"furniture\", \"advice\" uncountable — వీటికి plural ఉండదు. \"some information\"."}'::jsonb, '{"l1Form":"chala informations","l2Form":"a lot of information"}'::jsonb, ARRAY['He gave me many informations','We bought new furnitures']::text[]),
  ('te.universal_tag', 'Telugu', 'pragmatic', 'fn.tag_questions', 'Using "isn''t it?" as a universal tag', 'A single Telugu tag fits everything, so "isn''t it?" gets over-used.', '[{"kind":"regex","pattern":"isn''?t it\\b"}]'::jsonb, '{"Telugu":"ప్రతి వాక్యంలో \"isn''t it?\" పెట్టకండి. Subject, verb బట్టి మారుతుంది: \"You''re coming, aren''t you?\""}'::jsonb, '{"l1Form":"vastunnaru kada?","l2Form":"you''re coming, aren''t you?"}'::jsonb, ARRAY['You will join, isn''t it?','They are ready, isn''t it?']::text[]),
  ('te.theta', 'Telugu', 'phonetic', 'ph.theta_voiceless', 'The TH sound /θ/', 'Telugu has no /θ/, so "think" becomes "tink".', '[{"kind":"phoneme","pattern":"theta"}]'::jsonb, '{"Telugu":"\"think\", \"three\" లో /θ/ — నాలుకను పళ్ళ మధ్య పెట్టి గాలి వదలండి. \"t\" కాదు."}'::jsonb, '{"l1Form":"ట (t)","l2Form":"/θ/ think"}'::jsonb, ARRAY['tink','tree (three)']::text[]),
